const express = require('express');
const http = require('http');
const socketIo = require('socket.io');
const crypto = require('crypto');

const app = express();
const server = http.createServer(app);
const io = socketIo(server);

const SECRET_KEY = crypto.randomBytes(32).toString('hex');
const HMAC_ALGORITHM = 'sha256';

const sessions = new Map();
const players = new Map();
const leaderboard = new Map();

function generateSessionToken(username) {
  const timestamp = Date.now();
  const randomData = crypto.randomBytes(16).toString('hex');
  const data = `${username}:${timestamp}:${randomData}`;
  const hmac = crypto.createHmac(HMAC_ALGORITHM, SECRET_KEY);
  hmac.update(data);
  const signature = hmac.digest('hex');
  return `${Buffer.from(data).toString('base64')}.${signature}`;
}

function verifySessionToken(token) {
  try {
    const [dataB64, signature] = token.split('.');
    const data = Buffer.from(dataB64, 'base64').toString('utf8');
    
    const hmac = crypto.createHmac(HMAC_ALGORITHM, SECRET_KEY);
    hmac.update(data);
    const expectedSignature = hmac.digest('hex');
    
    if (!crypto.timingSafeEqual(Buffer.from(signature), Buffer.from(expectedSignature))) {
      return null;
    }
    
    const [username, timestamp] = data.split(':');
    const tokenAge = Date.now() - parseInt(timestamp);
    
    if (tokenAge > 24 * 60 * 60 * 1000) {
      return null;
    }
    
    return username;
  } catch (error) {
    return null;
  }
}

function generateScoreToken(username, score, timestamp) {
  const data = `${username}:${score}:${timestamp}`;
  const hmac = crypto.createHmac(HMAC_ALGORITHM, SECRET_KEY);
  hmac.update(data);
  return hmac.digest('hex');
}

function verifyScoreToken(username, score, timestamp, token) {
  const expectedToken = generateScoreToken(username, score, timestamp);
  try {
    return crypto.timingSafeEqual(Buffer.from(token), Buffer.from(expectedToken));
  } catch {
    return false;
  }
}

io.use((socket, next) => {
  const token = socket.handshake.auth.token;
  
  if (!token) {
    return next(new Error('Authentication required'));
  }
  
  const username = verifySessionToken(token);
  
  if (!username) {
    return next(new Error('Invalid or expired token'));
  }
  
  socket.username = username;
  socket.sessionToken = token;
  next();
});

io.on('connection', (socket) => {
  console.log(`Player connected: ${socket.username}`);
  
  sessions.set(socket.id, {
    username: socket.username,
    token: socket.sessionToken,
    connectedAt: Date.now(),
    lastActivity: Date.now()
  });
  
  players.set(socket.username, {
    socketId: socket.id,
    score: leaderboard.get(socket.username) || 0,
    online: true
  });
  
  socket.emit('authenticated', {
    username: socket.username,
    currentScore: players.get(socket.username).score
  });
  
  socket.emit('leaderboard', Array.from(leaderboard.entries())
    .sort((a, b) => b[1] - a[1])
    .slice(0, 10)
    .map(([username, score]) => ({ username, score }))
  );
  
  socket.on('submitScore', (data) => {
    const session = sessions.get(socket.id);
    
    if (!session) {
      socket.emit('error', { message: 'Invalid session' });
      return;
    }
    
    session.lastActivity = Date.now();
    
    const { score, timestamp, scoreToken } = data;
    
    if (typeof score !== 'number' || score < 0 || !Number.isInteger(score)) {
      socket.emit('error', { message: 'Invalid score format' });
      return;
    }
    
    if (!timestamp || !scoreToken) {
      socket.emit('error', { message: 'Missing score verification data' });
      return;
    }
    
    const timeDiff = Date.now() - timestamp;
    if (timeDiff < 0 || timeDiff > 60000) {
      socket.emit('error', { message: 'Score timestamp invalid' });
      return;
    }
    
    if (!verifyScoreToken(socket.username, score, timestamp, scoreToken)) {
      socket.emit('error', { message: 'Score verification failed' });
      return;
    }
    
    const player = players.get(socket.username);
    const currentScore = leaderboard.get(socket.username) || 0;
    
    if (score > currentScore) {
      leaderboard.set(socket.username, score);
      player.score = score;
      
      socket.emit('scoreUpdated', { score });
      
      io.emit('leaderboard', Array.from(leaderboard.entries())
        .sort((a, b) => b[1] - a[1])
        .slice(0, 10)
        .map(([username, score]) => ({ username, score }))
      );
    }
  });
  
  socket.on('getScoreToken', (data) => {
    const { score } = data;
    
    if (typeof score !== 'number' || score < 0 || !Number.isInteger(score)) {
      socket.emit('error', { message: 'Invalid score' });
      return;
    }
    
    const timestamp = Date.now();
    const scoreToken = generateScoreToken(socket.username, score, timestamp);
    
    socket.emit('scoreToken', { scoreToken, timestamp });
  });
  
  socket.on('disconnect', () => {
    console.log(`Player disconnected: ${socket.username}`);
    
    sessions.delete(socket.id);
    
    const player = players.get(socket.username);
    if (player) {
      player.online = false;
    }
  });
});

app.use(express.json());

app.post('/auth/login', (req, res) => {
  const { username } = req.body;
  
  if (!username || typeof username !== 'string' || username.length < 3 || username.length > 20) {
    return res.status(400).json({ error: 'Invalid username' });
  }
  
  const sanitizedUsername = username.replace(/[^a-zA-Z0-9_-]/g, '');
  
  if (sanitizedUsername !== username) {
    return res.status(400).json({ error: 'Username contains invalid characters' });
  }
  
  const token = generateSessionToken(sanitizedUsername);
  
  res.json({
    success: true,
    token,
    username: sanitizedUsername
  });
});

app.get('/leaderboard', (req, res) => {
  const top = Array.from(leaderboard.entries())
    .sort((a, b) => b[1] - a[1])
    .slice(0, 10)
    .map(([username, score]) => ({ username, score }));
  
  res.json({ leaderboard: top });
});

const PORT = process.env.PORT || 3000;

server.listen(PORT, () => {
  console.log(`Game server running on port ${PORT}`);
});